import{_ as s,H as t,f as l,i}from"./chunks/framework.BHvCMIhP.js";const c=JSON.parse('{"title":"终端工程系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"terminalLearning/00-写作计划.md","filePath":"terminalLearning/00-写作计划.md","lastUpdated":1779559313000}'),e={name:"terminalLearning/00-写作计划.md"};function n(o,a,r,p,d,h){return t(),l("div",null,[...a[0]||(a[0]=[i(`<h1 id="终端工程系列写作计划" tabindex="-1">终端工程系列写作计划 <a class="header-anchor" href="#终端工程系列写作计划" aria-label="Permalink to &quot;终端工程系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第三类「纵深主题」新增项,⭐⭐⭐⭐。 claudeLearning 教了「<strong>Claude Code 怎么用</strong>」,devopsLearning 教了「<strong>生产怎么跑</strong>」,gitLearning 教了「<strong>版本怎么管</strong>」,但都没回答一个核心问题:<strong>你每天在终端里的肌肉记忆,是怎么从一台机器复制到另一台、从去年用到明年、从本地推到远端的</strong>。 <strong>看完这层,你能让一台新机器在 30 分钟内变成你「家」的样子</strong>——tmux、Neovim、zsh、fzf、Nix、dotfiles、Claude Code,不再是一堆零散的工具名,而是知道每件解决什么问题、什么时候上、什么时候是过度配置。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>六层结构,从「心智」到「现代终端」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 + 基础(tty / pty / 进程 / 信号 / Unix 文本流哲学)</span></span>
<span class="line"><span>   → Shell 选型与日常(zsh / fish / 提示符 / 补全 / 历史)</span></span>
<span class="line"><span>   → 核心 CLI 工具链(grep-sed-awk → rg / fd / bat → fzf → jq → ssh)</span></span>
<span class="line"><span>   → Multiplexer + 编辑器(tmux / Zellij + Vim / Neovim / Helix)</span></span>
<span class="line"><span>   → Dotfiles 与可复现环境(chezmoi / Nix / mise / devcontainer)</span></span>
<span class="line"><span>   → 工作流深入(脚本工程化 / 任务运行器 / Claude Code 联动 / 现代终端)</span></span></code></pre></div><p><strong>这个系列不是 Linux 命令大全</strong>——<code>man</code> 还在那儿,你不需要再背一遍 <code>tar</code> 的 30 个 flag;<strong>默认你站在 2026 之后</strong>:大家都在 macOS / Linux 上用 zsh / fish + tmux + Neovim,Claude Code 已经是日常工作流的一部分,Nix / chezmoi 不再小众,Warp / Ghostty 重新定义了「终端是什么」。</p><p>不深入到 ncurses 源码、tty 设备驱动、glibc readline 内部,<strong>而是讲清楚&quot;应用工程师 / AI 工程师 / 全栈工程师能装、能改、能复现、能传承的工作流&quot;</strong>——你每天在终端里跑测试、写代码、调 Claude、远端登录、批处理日志,这些都站在这套工具链上。</p><hr><h2 id="篇目-30-篇" tabindex="-1">篇目(30 篇) <a class="header-anchor" href="#篇目-30-篇" aria-label="Permalink to &quot;篇目(30 篇)&quot;">​</a></h2><h3 id="第一层-心智与基础-01-04" tabindex="-1">第一层:心智与基础(01-04) <a class="header-anchor" href="#第一层-心智与基础-01-04" aria-label="Permalink to &quot;第一层:心智与基础(01-04)&quot;">​</a></h3><ul><li>[x] 01 终端工程总览(为什么终端是工程师的第二大脑 / 这套系列的目标读者)</li><li>[x] 02 终端的解剖(tty / pty / shell / 终端模拟器 / 一行命令背后发生了什么)</li><li>[x] 03 Unix 文本流哲学(管道 / 重定向 / stdin/stdout/stderr / 小工具组合大威力)</li><li>[x] 04 进程、作业与信号(fg / bg / jobs / SIGINT / SIGTERM / nohup / disown)</li></ul><h3 id="第二层-shell-选型与日常-05-09" tabindex="-1">第二层:Shell 选型与日常(05-09) <a class="header-anchor" href="#第二层-shell-选型与日常-05-09" aria-label="Permalink to &quot;第二层:Shell 选型与日常(05-09)&quot;">​</a></h3><ul><li>[x] 05 bash / zsh / fish 选型(POSIX 之痛 / zsh 兼容 / fish 走自己的路)</li><li>[x] 06 zsh 工程化配置(zinit / oh-my-zsh / 不用框架也行 / 启动速度调优)</li><li>[x] 07 提示符工程(Starship / Powerlevel10k / 异步渲染 / git 状态)</li><li>[x] 08 自动补全、别名与函数(compdef / abbr / 别名滥用是配置债)</li><li>[x] 09 历史命令的工具化(HISTFILE 心智 / fzf-history / atuin / mcfly)</li></ul><h3 id="第三层-核心-cli-工具链-10-15" tabindex="-1">第三层:核心 CLI 工具链(10-15) <a class="header-anchor" href="#第三层-核心-cli-工具链-10-15" aria-label="Permalink to &quot;第三层:核心 CLI 工具链(10-15)&quot;">​</a></h3><ul><li>[x] 10 文本三剑客 grep / sed / awk(2026 还要不要学 / 心智模型 / 何时换现代替代品)</li><li>[x] 11 现代替代品速通(rg / fd / bat / eza / dust / sd / procs / hyperfine)</li><li>[x] 12 fzf 心智(模糊匹配是 UI 模式 / 嵌入到一切命令里)</li><li>[x] 13 结构化数据处理(jq / yq / xsv / miller / dasel)</li><li>[x] 14 网络调试一线工具(curl / httpie / xh / dig / nc / mtr)</li><li>[x] 15 ssh 深用(config / ProxyJump / 端口转发 / 隧道 / mosh / 密钥管理)</li></ul><h3 id="第四层-multiplexer-与编辑器-16-21" tabindex="-1">第四层:Multiplexer 与编辑器(16-21) <a class="header-anchor" href="#第四层-multiplexer-与编辑器-16-21" aria-label="Permalink to &quot;第四层:Multiplexer 与编辑器(16-21)&quot;">​</a></h3><ul><li>[x] 16 tmux 心智(session / window / pane / 一次 attach 终身受益)</li><li>[x] 17 tmux 工作流配置(prefix / copy-mode / 持久化 / 跨终端共享)</li><li>[x] 18 Zellij vs tmux(声明式 layout / 内置 floating / 该不该迁移)</li><li>[x] 19 modal editing 的本质(vim 为什么是对的 / 命令是语法不是快捷键)</li><li>[x] 20 Neovim 现代配置(LazyVim / lspconfig / treesitter / dap / which-key)</li><li>[x] 21 Helix:开箱即用的 modal editor(选区先于动作 / 不打算抄 vim)</li></ul><h3 id="第五层-dotfiles-与可复现环境-22-26" tabindex="-1">第五层:Dotfiles 与可复现环境(22-26) <a class="header-anchor" href="#第五层-dotfiles-与可复现环境-22-26" aria-label="Permalink to &quot;第五层:Dotfiles 与可复现环境(22-26)&quot;">​</a></h3><ul><li>[x] 22 Dotfiles 心智与方案选型(裸 git / stow / chezmoi / yadm / 选型逻辑)</li><li>[x] 23 包管理器对比(brew / apt / pacman / paru / pnpm 不算这层)</li><li>[x] 24 多语言版本管理(mise / asdf / nvm / pyenv 为什么都被吃掉)</li><li>[x] 25 Nix 心智(纯函数式包管理 / flake / home-manager / 可复现的尽头)</li><li>[x] 26 Devcontainer 与 Remote dev(VS Code Remote / SSH / 容器化开发环境)</li></ul><h3 id="第六层-工作流深入与现代终端-27-30" tabindex="-1">第六层:工作流深入与现代终端(27-30) <a class="header-anchor" href="#第六层-工作流深入与现代终端-27-30" aria-label="Permalink to &quot;第六层:工作流深入与现代终端(27-30)&quot;">​</a></h3><ul><li>[x] 27 Shell 脚本工程化(set -euo pipefail / shellcheck / shfmt / bats 测试)</li><li>[x] 28 任务运行器选型(Make / Just / Task / mise tasks / npm-style)</li><li>[x] 29 终端 + Claude Code 工作流(tmux 多窗格 / fzf 选文件 / 远端 attach / 长跑后台)</li><li>[x] 30 现代终端的未来(Warp / WezTerm / Ghostty / Kitty / AI 原生终端往哪走)</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>git 命令 / 工作流</td><td>gitLearning ✅</td><td>不重复,只在 22 dotfiles 用裸 git 时点名</td></tr><tr><td>Vim 语法 / 操作</td><td>暂无</td><td>19-21 讲 modal editing 心智,不写「vim 100 个快捷键」</td></tr><tr><td>Docker / K8s</td><td>backendLearning ✅</td><td>不重复,26 只讲 devcontainer 作为远端开发环境</td></tr><tr><td>Linux 系统调用 / 进程模型</td><td>osLearning ✅</td><td>不重复,02、04 只点必要的概念</td></tr><tr><td>网络协议 / TCP / TLS</td><td>networkLearning ✅</td><td>不重复,14、15 只讲调试工具的使用</td></tr><tr><td>Claude Code 内部机制</td><td>claudeLearning ✅</td><td>不重复,29 讲「终端这一侧」如何接 Claude Code</td></tr><tr><td>CI/CD / GitOps</td><td>devopsLearning ✅</td><td>不重复,28 任务运行器只讲本地开发</td></tr><tr><td>Rust / Go CLI 工具开发</td><td>rustLearning / goLearning ✅</td><td>不重复,本系列是「用」CLI,不教「写」CLI</td></tr><tr><td>Shell 脚本算法题</td><td>algorithmLearning ✅</td><td>不重复,27 只讲脚本工程化(不写 awk 算 LeetCode)</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇遵守&quot;为什么这个工具 → 心智模型 → 最小配置 → 替代方案与局限&quot;的四段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 为什么这个工具存在</span></span>
<span class="line"><span>   - 没它的世界长什么样(上一代是谁,死在哪)</span></span>
<span class="line"><span>   - 它解决的根本问题是什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 心智模型(一张图 / 一段对照)</span></span>
<span class="line"><span>   - 概念图 / 数据流 / 状态机,任选其一</span></span>
<span class="line"><span>   - 关键概念用最少的名词讲清楚</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 最小配置(能用、能改、能复现)</span></span>
<span class="line"><span>   - 贴 10-30 行真能跑的配置或脚本</span></span>
<span class="line"><span>   - 标注「这一行如果删掉会怎样」</span></span>
<span class="line"><span>   - 调优 / 排错的关键开关</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 替代方案与局限</span></span>
<span class="line"><span>   - 同代位竞争者(tmux vs Zellij / Neovim vs Helix / Nix vs mise)</span></span>
<span class="line"><span>   - 什么场景不该用它</span></span>
<span class="line"><span>   - 2026 之后业界往哪个方向走</span></span></code></pre></div><p>不抄官方 README——<strong>只贴让读者「看到这一行配置改了什么」的最小片段</strong>,让读者「拿走就能用」。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-04  心智:看完知道&quot;一次按键到屏幕显示之间发生了什么,信号到底是 SIGINT 还是 SIGTERM&quot;</span></span>
<span class="line"><span>05-09  Shell:看完知道&quot;为什么 zsh 启动慢、补全是怎么回事、历史命令为什么必须用 atuin&quot;</span></span>
<span class="line"><span>10-15  CLI:看完知道&quot;为什么 rg 比 grep 快 10 倍,fzf 嵌进所有命令是怎么做到的&quot;</span></span>
<span class="line"><span>16-21  Multiplexer + 编辑器:**生产力的真正护城河**,tmux + Neovim 一旦内化就回不去了</span></span>
<span class="line"><span>22-26  环境管理:**新机器半小时复刻**,Nix / chezmoi / mise 决定你能不能&quot;换机不换工作流&quot;</span></span>
<span class="line"><span>27-30  工作流:**和 Claude Code / AI 工作流结合**,看完知道&quot;终端的下一站长什么样&quot;</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 16-26 这 11 篇,你应该能在一台干净的新 Mac / Linux 上,30 分钟内:</p><ul><li>装好包管理器 + dotfiles 一键 sync</li><li>tmux 配置 + 字体 + 主题 + 提示符全部到位</li><li>Neovim / Helix 打开就能写代码 + 跑 LSP</li><li>ssh config 就绪,远端机器一键 attach</li><li>Claude Code 能在 tmux pane 里跑长任务,自己回头看输出</li></ul><p>能做到这个,这个系列就值了。</p><p>再加上 27-30 这 4 篇,你应该能讲清楚:</p><ul><li>&quot;为什么 just 比 Makefile 更适合 2026 的项目,什么时候还是该用 Make&quot;</li><li>&quot;Warp / Ghostty / WezTerm 各自赌的是哪条路,选型该看什么&quot;</li><li>&quot;Claude Code 跟终端工作流之间该怎么编排,才不会变成新型号的&#39;写满 IDE 的 monorepo&#39;&quot;</li></ul><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li><strong>不写 Linux 命令大全 / man 复印件</strong>——<code>man</code> 在那儿,本系列只在工具有反直觉之处插一句「这里坑在哪」</li><li>「先讲个 Unix 起源故事 / Bell Labs / Multics」——直接进重点,历史只在脚注引用</li><li>罗列工具的全部 flag——只贴「让读者用得起来」的最小子集</li><li>「这个工具我用了 N 年」式个人安利——读者关心选型逻辑,不关心你的情怀</li><li><strong>不画图就讲 tty / pty / 进程组 / tmux 嵌套</strong>——这些东西<strong>不画图永远讲不清楚</strong></li><li>抄 oh-my-zsh / LazyVim 的官方 README——官方文档在那儿,这里只补它没讲透的「为什么」和「什么时候不要用」</li><li>「vim vs emacs 谁更牛」式的口水战——只讲各自擅长的场景,选型留给工程判断</li><li>把「我的 dotfiles」当核心内容——本系列的目标是让读者建立自己的工作流,不是抄一份回去</li></ol><hr><h2 id="立场声明" tabindex="-1">立场声明 <a class="header-anchor" href="#立场声明" aria-label="Permalink to &quot;立场声明&quot;">​</a></h2><p>本系列<strong>只服务于工程视角</strong>——能装、能改、能复现、能传给团队新人。</p><p>所有示例配置限制在最小可跑片段,<strong>不教你怎么从零写一个 1000 行的 .zshrc 或 init.lua</strong>——那是个人审美,本系列的读者画像是「想把终端工作流系统化的工程师」,你需要懂这些工具是怎么编排的,但不需要花一个周末抄完别人的 dotfiles 再调一周。</p><p><strong>面向 2026:</strong></p><ul><li>macOS / Linux 双平台,不写 Windows(WSL 除外,放在 26 一句话带过)</li><li>默认 Apple Silicon / x86_64,不写远古架构</li><li>默认你已经会用 git,系列里不重复教</li><li>默认你已经在用 Claude Code,29 篇直接讲怎么和终端工作流接起来</li></ul>`,48)])])}const m=s(e,[["render",n]]);export{c as __pageData,m as default};
